/* eslint-disable react-hooks/exhaustive-deps */
import { jwtDecode } from 'jwt-decode';
import { useEffect } from 'react';
import { useDispatch } from 'react-redux';
import { BrowserRouter } from 'react-router-dom';
import { MotionLazy } from 'src/components/animate/motion-lazy';
import { ProgressBar } from 'src/components/progress-bar';
import { defaultSettings, SettingsDrawer, SettingsProvider } from 'src/components/settings';
import { Snackbar } from 'src/components/snackbar';
import 'src/global.css';
import { LocalizationProvider } from 'src/locales';
import { I18nProvider } from 'src/locales/i18n-provider';
import { themeConfig, ThemeProvider } from 'src/theme';
import utils from 'src/utils/utils';
import { useNavigate } from 'react-router';

import apiService from './services/ApiService';
import './services/AxiosService';
import { login, logout, setTenantDetail } from './store/reducers/authReducer';

export default function App({ children }) {
  const dispatch = useDispatch();
  const tenantDetail = utils.getItemFromStorage('tenantDetail');
  const navigate = useNavigate();
  defaultSettings.primaryColor = tenantDetail && tenantDetail.primaryColor;
  useEffect(() => {
    bindInitData();
    updateFavicon();
  }, []);

  const bindInitData = async () => {
    const token = utils.getTokensFromStorage();
    dispatch(setTenantDetail(JSON.parse(tenantDetail)));
    let currentTokenUser = token && jwtDecode(token.session);
    if (currentTokenUser) {
      dispatch(login({ teacher: currentTokenUser, token }));
      // const { data } = await apiService.getUserInitializeAsync();
      // if (data && data.user && data.user.isTenantActive) {
      //   const user = { ...currentTokenUser, ...data.user };
      //   dispatch(login({ user, token }));
      // }
    } else {
      dispatch(logout());
    }
  };

  const updateFavicon = () => {
    if (tenantDetail) {
      const tenant = JSON.parse(tenantDetail);
      const faviconUrl = tenant && tenant.faviconUrl;
      if (faviconUrl) {
        const link = document.getElementById('favicon');
        if (link) {
          link.href = faviconUrl;
        } else {
          const newLink = document.createElement('link');
          newLink.id = 'favicon';
          newLink.rel = 'icon';
          newLink.type = 'image/x-icon';
          newLink.href = faviconUrl;
          document.head.appendChild(newLink);
        }
      }
    }
  };

  return (
    <BrowserRouter>
      <I18nProvider>
        <SettingsProvider defaultSettings={defaultSettings}>
          <LocalizationProvider>
            <ThemeProvider
              noSsr
              defaultMode={themeConfig.defaultMode}
              modeStorageKey={themeConfig.modeStorageKey}
            >
              <MotionLazy>
                <Snackbar />
                <ProgressBar />
                <SettingsDrawer defaultSettings={defaultSettings} />
                {children}
              </MotionLazy>
            </ThemeProvider>
          </LocalizationProvider>
        </SettingsProvider>
      </I18nProvider>
    </BrowserRouter>
  );
}

import { useState } from 'react';
import { useSelector } from 'react-redux';
import { usePathname, useRouter } from 'src/routes/hooks';
import { paths } from 'src/routes/paths';

import { RoleBasedGuard } from '.';

const signInPaths = { jwt: paths.auth.signIn };

export function AuthGuard({ children }) {
  const router = useRouter();
  const pathname = usePathname();

  const { loggedInTeacher } = useSelector((state) => state.AuthReducer);
  const [isChecking, setIsChecking] = useState(true);
  const [isCheckPermission, setIsCheckPermission] = useState(true);

  const createRedirectPath = (currentPath) => {
    const queryString = new URLSearchParams({ returnTo: pathname }).toString();
    return `${currentPath}?${queryString}`;
  };

  if (!isCheckPermission) {
    return <RoleBasedGuard hasContent sx={{ py: 10 }} />;
  }

  return <>{children}</>;
}

import { useState, useEffect } from 'react';
import { useRouter, useSearchParams } from 'src/routes/hooks';
import { CONFIG } from 'src/global-config';
import { SplashScreen } from 'src/components/loading-screen';
import { useSelector } from 'react-redux';
import enums from 'src/utils/enums';

// ----------------------------------------------------------------------

export function GuestGuard({ children }) {
  const router = useRouter();

  const searchParams = useSearchParams();
  const returnTo = searchParams.get('returnTo') || CONFIG.auth.redirectPath;
  const { loggedInUser } = useSelector((state) => state.AuthReducer);

  const [isChecking, setIsChecking] = useState(true);
  const checkPermissions = async () => {
    if (loggedInUser) {
      if (returnTo === '/' || returnTo === '/dashboard') {
        router.replace('/dashboard/tenant');
      } else {
        router.replace(returnTo);
      }
      return;
    }
    setIsChecking(false);
  };

  useEffect(() => {
    checkPermissions();
  }, [loggedInUser]);

  if (isChecking) {
    return <SplashScreen />;
  }

  return <>{children}</>;
}

import { m } from 'framer-motion';
import Container from '@mui/material/Container';
import Typography from '@mui/material/Typography';
import { ForbiddenIllustration } from 'src/assets/illustrations';
import { varBounce, MotionContainer } from 'src/components/animate';
import { Button } from '@mui/material';
import { RouterLink } from 'src/routes/components';

// ----------------------------------------------------------------------

export function RoleBasedGuard({ sx, children, hasContent }) {
  return hasContent ? (
    <Container
      component={MotionContainer}
      sx={[{ textAlign: 'center' }, ...(Array.isArray(sx) ? sx : [sx])]}
    >
      <m.div variants={varBounce('in')}>
        <Typography variant="h3" sx={{ mb: 2 }}>
          Permission denied
        </Typography>
      </m.div>

      <m.div variants={varBounce('in')}>
        <Typography sx={{ color: 'text.secondary' }}>
          You do not have permission to access this page.
        </Typography>
      </m.div>

      <m.div variants={varBounce('in')}>
        <ForbiddenIllustration sx={{ my: { xs: 5, sm: 10 } }} />
      </m.div>
      <Button component={RouterLink} href={-1} size="large" variant="contained">
        Go to home
      </Button>
    </Container>
  ) : null;
}

import { z as zod } from 'zod';
import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { useBoolean } from 'minimal-shared/hooks';
import { zodResolver } from '@hookform/resolvers/zod';
import Box from '@mui/material/Box';
import Link from '@mui/material/Link';
import Alert from '@mui/material/Alert';
import IconButton from '@mui/material/IconButton';
import LoadingButton from '@mui/lab/LoadingButton';
import InputAdornment from '@mui/material/InputAdornment';
import { paths } from 'src/routes/paths';
import { useRouter } from 'src/routes/hooks';
import { RouterLink } from 'src/routes/components';
import { Iconify } from 'src/components/iconify';
import { Form, Field, schemaHelper } from 'src/components/hook-form';
import { isValidPhoneNumber } from 'react-phone-number-input';
import apiService from 'src/services/ApiService';
import { dispatch } from 'src/store';
import { login } from 'src/store/reducers/authReducer';
import { useNavigate } from 'react-router';

import { FormHead } from '../../components/form-head';
import { getErrorMessage } from '../../utils';

// ----------------------------------------------------------------------

export const SignUpSchema = zod.object({
  firstName: zod.string().min(1, { message: 'First name is required.' }),
  surName: zod.string().min(1, { message: 'Surname is required.' }),
  email: zod
    .string()
    .min(1, { message: 'Email is required.' })
    .email({ message: 'Email must be a valid email address.' }),
  password: zod
    .string()
    .min(1, { message: 'Password is required.' })
    .min(6, { message: 'Password must be at least 6 characters.' }),
  phone: schemaHelper.phoneNumber({ isValid: isValidPhoneNumber }),
  pin: zod
    .string()
    .trim()
    .min(6, { message: 'Pin must have six characters.' })
    .regex(/^[0-9]+$/, { message: 'Pin should not contain special characters.' })
    .optional(),
});

// ----------------------------------------------------------------------

export function JwtSignUpView() {
  const router = useRouter();
  const navigate = useNavigate();
  const showPassword = useBoolean();

  const [errorMessage, setErrorMessage] = useState('');

  const defaultValues = {
    firstName: '',
    surName: '',
    email: '',
    password: '',
    phone: '',
    pin: '',
  };

  const methods = useForm({
    resolver: zodResolver(SignUpSchema),
    defaultValues,
  });

  const {
    handleSubmit,
    formState: { isSubmitting },
  } = methods;

  // const createRedirectPath = (query) => {
  //   const queryString = new URLSearchParams({ email: query }).toString();

  //   return `${paths.auth.verify}?${queryString}`;
  // };

  const onSubmit = handleSubmit(async (values) => {
    try {
      const { data, errors } = await apiService.signUpAsync(values);
      if (data) {
        const token = { session: data.session, refresh: data.refresh };
        dispatch(login({ user: data.user, token }));
        navigate('/dashboard');
      } else if (errors) {
        errors.map((error) => {
          setErrorMessage(error.msg);
        });
      }
    } catch (error) {
      console.error(error);
      const feedbackMessage = getErrorMessage(error);
      setErrorMessage(feedbackMessage);
    }
  });

  const renderForm = () => (
    <Box sx={{ gap: 3, display: 'flex', flexDirection: 'column' }}>
      <Box
        sx={{ display: 'flex', gap: { xs: 3, sm: 2 }, flexDirection: { xs: 'column', sm: 'row' } }}
      >
        <Field.Text
          name="firstName"
          label="First name"
          slotProps={{ inputLabel: { shrink: true } }}
        />

        <Field.Text name="surName" label="Surname" slotProps={{ inputLabel: { shrink: true } }} />
      </Box>

      <Field.Text name="email" label="Email address" slotProps={{ inputLabel: { shrink: true } }} />

      <Field.Text
        name="password"
        label="Password"
        placeholder="6+ characters"
        type={showPassword.value ? 'text' : 'password'}
        slotProps={{
          inputLabel: { shrink: true },

          input: {
            endAdornment: (
              <InputAdornment position="end">
                <IconButton onClick={showPassword.onToggle} edge="end">
                  <Iconify icon={showPassword.value ? 'solar:eye-bold' : 'solar:eye-closed-bold'} />
                </IconButton>
              </InputAdornment>
            ),
          },
        }}
      />
      <Field.Phone name="phone" label="Phone number" />
      <Field.Text
        name="pin"
        label="Pin"
        slotProps={{ inputLabel: { shrink: true }, htmlInput: { maxLength: 6 } }}
      />

      <LoadingButton
        fullWidth
        color="inherit"
        size="large"
        type="submit"
        variant="contained"
        loading={isSubmitting}
        loadingIndicator="Create account..."
      >
        Create account
      </LoadingButton>
    </Box>
  );

  return (
    <>
      <FormHead
        title="Get started by sign-up"
        description={
          <>
            {`Already have an account? `}

            <Link component={RouterLink} href={paths.auth.signIn} variant="subtitle2">
              Get started
            </Link>
          </>
        }
        sx={{ textAlign: { xs: 'center', md: 'left' } }}
      />

      {!!errorMessage && (
        <Alert severity="error" sx={{ mb: 3 }}>
          {errorMessage}
        </Alert>
      )}

      <Form methods={methods} onSubmit={onSubmit}>
        {renderForm()}
      </Form>
    </>
  );
}

import { mergeClasses } from 'minimal-shared/utils';
import { Children, forwardRef, isValidElement } from 'react';
import { styled } from '@mui/material/styles';

import { carouselClasses } from '../classes';

import { CarouselSlide } from './carousel-slide';

// ----------------------------------------------------------------------

export const CarouselThumbs = forwardRef((props, ref) => {
  const { children, slotProps, options, sx, className, ...other } = props;

  const axis = options?.axis ?? 'x';
  const slideSpacing = options?.slideSpacing ?? '12px';

  const renderChildren = () =>
    Children.map(children, (child) => {
      if (isValidElement(child)) {
        const reactChild = child;

        return (
          <CarouselSlide
            key={reactChild.key}
            options={{ ...options, slideSpacing }}
            sx={slotProps?.slide}
          >
            {child}
          </CarouselSlide>
        );
      }
      return null;
    });

  return (
    <ThumbsRoot
      ref={ref}
      axis={axis}
      enableMask={!slotProps?.disableMask}
      className={mergeClasses([carouselClasses.thumbs.root, className])}
      sx={sx}
      {...other}
    >
      <ThumbsContainer
        axis={axis}
        slideSpacing={slideSpacing}
        className={carouselClasses.thumbs.container}
        sx={slotProps?.container}
      >
        {renderChildren()}
      </ThumbsContainer>
    </ThumbsRoot>
  );
});

// ----------------------------------------------------------------------

const ThumbsRoot = styled('div', {
  shouldForwardProp: (prop) => !['axis', 'enableMask', 'sx'].includes(prop),
})(({ enableMask, theme }) => {
  const maskBg = `${theme.vars.palette.background.paper} 20%, transparent 100%)`;

  return {
    flexShrink: 0,
    margin: 'auto',
    maxWidth: '100%',
    overflow: 'hidden',
    position: 'relative',
    variants: [
      {
        props: { axis: 'x' },
        style: {
          maxWidth: '100%',
          padding: theme.spacing(0.5),
          ...(enableMask && {
            '&::before, &::after': {
              top: 0,
              zIndex: 9,
              width: 40,
              content: '""',
              height: '100%',
              position: 'absolute',
            },
            '&::before': {
              left: -8,
              background: `linear-gradient(to right, ${maskBg}`,
            },
            '&::after': {
              right: -8,
              background: `linear-gradient(to left, ${maskBg}`,
            },
          }),
        },
      },
      {
        props: { axis: 'y' },
        style: {
          height: '100%',
          maxHeight: '100%',
          padding: theme.spacing(0.5),
          ...(enableMask && {
            '&::before, &::after': {
              left: 0,
              zIndex: 9,
              height: 40,
              content: '""',
              width: '100%',
              position: 'absolute',
            },
            '&::before': {
              top: -8,
              background: `linear-gradient(to bottom, ${maskBg}`,
            },
            '&::after': {
              bottom: -8,
              background: `linear-gradient(to top, ${maskBg}`,
            },
          }),
        },
      },
    ],
  };
});

const ThumbsContainer = styled('ul', {
  shouldForwardProp: (prop) => !['axis', 'slideSpacing', 'sx'].includes(prop),
})(({ slideSpacing }) => ({
  display: 'flex',
  backfaceVisibility: 'hidden',
  variants: [
    {
      props: { axis: 'x' },
      style: {
        touchAction: 'pan-y pinch-zoom',
        marginLeft: `calc(${slideSpacing} * -1)`,
      },
    },
    {
      props: { axis: 'y' },
      style: {
        height: '100%',
        flexDirection: 'column',
        touchAction: 'pan-x pinch-zoom',
        marginTop: `calc(${slideSpacing} * -1)`,
      },
    },
  ],
}));

import { TextField } from '@mui/material';
import { useEffect, useState } from 'react';
import DatePicker from 'react-datepicker';
import 'react-datepicker/dist/react-datepicker.css';
import dateHelper from 'src/utils/dateHelper';

export default function DateRangePicker({
  showDateRangePicker,
  onDateChanges,
  minDate,
  maxDate,
  resetDuration,
  sDate,
  eDate,
}) {
  const [startDate, setStartDate] = useState(sDate);
  const [endDate, setEndDate] = useState(eDate);
  const [textValue, setTextValue] = useState('mm/dd/yyyy - mm/dd/yyyy');
  const [isDatePickerOpen, setIsDatePickerOpen] = useState(false);

  useEffect(() => {
    if (sDate || eDate) {
      setStartDate(sDate);
      setEndDate(eDate);
      if (sDate && eDate) {
        setTextValue(`${dateHelper.formatDate(sDate)} - ${dateHelper.formatDate(eDate)}`);
      }
    }
  }, [sDate, eDate]);

  useEffect(() => {
    if (showDateRangePicker && resetDuration) {
      setStartDate(null);
      setEndDate(null);
      setTextValue('mm/dd/yyyy - mm/dd/yyyy');
    }
    if (startDate === null && endDate === null) {
      setIsDatePickerOpen(true);
    }
  }, [showDateRangePicker, resetDuration]);

  const onDateChange = (dates) => {
    const [start, end] = dates;
    setStartDate(start);
    setEndDate(end);
    if (start && end) {
      setIsDatePickerOpen(false);
      setTextValue(`${dateHelper.formatDate(start)} - ${dateHelper.formatDate(end)}`);
      onDateChanges(start, end);
    }
  };

  if (!showDateRangePicker) return null;

  return (
    <DatePicker
      open={isDatePickerOpen}
      selected={startDate}
      onChange={onDateChange}
      startDate={startDate}
      endDate={endDate}
      minDate={minDate}
      maxDate={maxDate}
      dateFormat={'MM/dd/yyyy'}
      selectsRange
      showYearDropdown
      showMonthDropdown
      customInput={
        <TextField
          label="Between"
          variant="standard"
          value={textValue}
          sx={{ width: 200 }}
          InputProps={{
            onFocus: () => setIsDatePickerOpen(true),
          }}
        />
      }
    />
  );
}

import Autocomplete from '@mui/material/Autocomplete';
import TextField from '@mui/material/TextField';
import { Controller, useFormContext } from 'react-hook-form';

// ----------------------------------------------------------------------

export function RHFAutocomplete({ name, label, slotProps, helperText, placeholder, ...other }) {
  const { control, setValue, watch } = useFormContext();
  const value = watch(name);
  const { textfield, ...otherSlotProps } = slotProps ?? {};

  return (
    <Controller
      name={name}
      control={control}
      render={({ field, fieldState: { error } }) => (
        <Autocomplete
          {...field}
          id={`rhf-autocomplete-${name}`}
          disableClearable={other.disableClearable ?? (!value || value.length === 0)}
          value={other.options?.find((opt) => opt.value === field.value) || null}
          onChange={(_, newValue) => field.onChange(newValue ? newValue.value : '')}
          getOptionLabel={(option) => {
            if (!option) return '';
            if (typeof option === 'string') return option;
            return option.label || '';
          }}
          isOptionEqualToValue={(option, value) => option.value === value.value}
          renderInput={(params) => (
            <TextField
              {...params}
              {...textfield}
              label={label}
              placeholder={placeholder}
              error={!!error}
              helperText={error?.message ?? helperText}
              slotProps={{
                ...textfield?.slotProps,
                htmlInput: {
                  ...params.inputProps,
                  autoComplete: 'off',
                  ...textfield?.slotProps?.htmlInput,
                },
              }}
            />
          )}
          {...other}
          {...otherSlotProps}
        />
      )}
    />
  );
}

/* eslint-disable react/display-name */
import ButtonBase from '@mui/material/ButtonBase';
import Tooltip from '@mui/material/Tooltip';
import { styled } from '@mui/material/styles';
import { mergeClasses } from 'minimal-shared/utils';
import { forwardRef } from 'react';
import { useNavigate } from 'react-router-dom';

import { Iconify } from '../../iconify';
import { navItemStyles, navSectionClasses } from '../styles';
import { createNavItem } from '../utils';

// ----------------------------------------------------------------------

export const NavItem = forwardRef((props, ref) => {
  const {
    path,
    icon,
    info,
    title,
    caption,
    /********/
    open,
    active,
    disabled,
    /********/
    depth,
    render,
    hasChild,
    slotProps,
    className,
    externalLink,
    enabledRootRedirect,
    ...other
  } = props;

  const navigate = useNavigate();
  const navItem = createNavItem({
    path,
    icon,
    info,
    depth,
    render,
    hasChild,
    externalLink,
    enabledRootRedirect,
  });

  const ownerState = {
    open,
    active,
    disabled,
    variant: navItem.rootItem ? 'rootItem' : 'subItem',
  };

  const handleClick = (e) => {
    // always navigate to clean path (no querystring)
    navigate(path, { replace: false });
  };

  return (
    <ItemRoot
      onClick={handleClick}
      ref={ref}
      aria-label={title}
      {...ownerState}
      {...navItem.baseProps}
      className={mergeClasses([navSectionClasses.item.root, className], {
        [navSectionClasses.state.open]: open,
        [navSectionClasses.state.active]: active,
        [navSectionClasses.state.disabled]: disabled,
      })}
      sx={slotProps?.sx}
      {...other}
    >
      {icon && (
        <ItemIcon {...ownerState} className={navSectionClasses.item.icon} sx={slotProps?.icon}>
          {navItem.renderIcon}
        </ItemIcon>
      )}

      {title && (
        <ItemTitle {...ownerState} className={navSectionClasses.item.title} sx={slotProps?.title}>
          {title}
        </ItemTitle>
      )}

      {caption && (
        <Tooltip title={caption} arrow>
          <ItemCaptionIcon
            {...ownerState}
            icon="eva:info-outline"
            className={navSectionClasses.item.caption}
            sx={slotProps?.caption}
          />
        </Tooltip>
      )}

      {info && (
        <ItemInfo {...ownerState} className={navSectionClasses.item.info} sx={slotProps?.info}>
          {navItem.renderInfo}
        </ItemInfo>
      )}

      {hasChild && (
        <ItemArrow
          {...ownerState}
          icon={navItem.subItem ? 'eva:arrow-ios-forward-fill' : 'eva:arrow-ios-downward-fill'}
          className={navSectionClasses.item.arrow}
          sx={slotProps?.arrow}
        />
      )}
    </ItemRoot>
  );
});

// ----------------------------------------------------------------------

const shouldForwardProp = (prop) => !['open', 'active', 'disabled', 'variant', 'sx'].includes(prop);

/**
 * @slot root
 */
const ItemRoot = styled(ButtonBase, { shouldForwardProp })(({ active, open, theme }) => {
  const rootItemStyles = {
    padding: 'var(--nav-item-root-padding)',
    minHeight: 'var(--nav-item-root-height)',
    ...(open && {
      color: 'var(--nav-item-root-open-color)',
      backgroundColor: 'var(--nav-item-root-open-bg)',
    }),
    ...(active && {
      color: 'var(--nav-item-root-active-color)',
      backgroundColor: 'var(--nav-item-root-active-bg)',
      '&:hover': { backgroundColor: 'var(--nav-item-root-active-hover-bg)' },
      ...theme.applyStyles('dark', {
        color: 'var(--nav-item-root-active-color-on-dark)',
      }),
    }),
  };

  const subItemStyles = {
    padding: 'var(--nav-item-sub-padding)',
    minHeight: 'var(--nav-item-sub-height)',
    color: theme.vars.palette.text.secondary,
    ...(open && {
      color: 'var(--nav-item-sub-open-color)',
      backgroundColor: 'var(--nav-item-sub-open-bg)',
    }),
    ...(active && {
      color: 'var(--nav-item-sub-active-color)',
      backgroundColor: 'var(--nav-item-sub-active-bg)',
    }),
  };

  return {
    width: '100%',
    flexShrink: 0,
    color: 'var(--nav-item-color)',
    borderRadius: 'var(--nav-item-radius)',
    '&:hover': { backgroundColor: 'var(--nav-item-hover-bg)' },
    variants: [
      { props: { variant: 'rootItem' }, style: rootItemStyles },
      { props: { variant: 'subItem' }, style: subItemStyles },
      { props: { disabled: true }, style: navItemStyles.disabled },
    ],
  };
});

/**
 * @slot icon
 */
const ItemIcon = styled('span', { shouldForwardProp })(() => ({
  ...navItemStyles.icon,
  width: 'var(--nav-icon-size)',
  height: 'var(--nav-icon-size)',
  margin: 'var(--nav-icon-root-margin)',
  variants: [{ props: { variant: 'subItem' }, style: { margin: 'var(--nav-icon-sub-margin)' } }],
}));

/**
 * @slot title
 */
const ItemTitle = styled('span', { shouldForwardProp })(({ theme }) => ({
  ...navItemStyles.title(theme),
  ...theme.typography.body2,
  fontWeight: theme.typography.fontWeightMedium,
  variants: [
    { props: { active: true }, style: { fontWeight: theme.typography.fontWeightSemiBold } },
  ],
}));

/**
 * @slot caption icon
 */
const ItemCaptionIcon = styled(Iconify, { shouldForwardProp })(({ theme }) => ({
  ...navItemStyles.captionIcon,
  color: 'var(--nav-item-caption-color)',
  variants: [{ props: { variant: 'rootItem' }, style: { marginLeft: theme.spacing(0.75) } }],
}));

/**
 * @slot info
 */
const ItemInfo = styled('span', { shouldForwardProp })(() => ({
  ...navItemStyles.info,
}));

