function Group({
  items,
  render,
  subheader,
  slotProps,
  currentRole,
  enabledRootRedirect,
  loggedInTeacher,
}) {
  const groupOpen = useBoolean(true);

  const renderContent = () => (
    <NavUl sx={{ gap: 'var(--nav-item-gap)' }}>
      {items.map((list) => (
        <NavList
          key={list.title}
          data={list}
          render={render}
          depth={1}
          slotProps={slotProps}
          currentRole={currentRole}
          enabledRootRedirect={enabledRootRedirect}
        />
      ))}
    </NavUl>
  );

  return (
    <NavLi>
      {subheader && !(subheader === 'Overview') ? (
        <>
          <NavSubheader
            data-title={subheader}
            open={groupOpen.value}
            onClick={groupOpen.onToggle}
            sx={slotProps?.subheader}
          >
            {subheader}
          </NavSubheader>

          <Collapse in={groupOpen.value}>{renderContent()}</Collapse>
        </>
      ) : (
        renderContent()
      )}
    </NavLi>
  );
}

import { isEqual } from 'es-toolkit';
import { useLocalStorage } from 'minimal-shared/hooks';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { useSelector } from 'react-redux';

import { SETTINGS_STORAGE_KEY } from '../settings-config';

import { SettingsContext } from './settings-context';

// ----------------------------------------------------------------------

export function SettingsProvider({
  children,
  defaultSettings: baseSettings,
  storageKey = SETTINGS_STORAGE_KEY,
}) {
  const { tenantDetail } = useSelector((state) => state.AuthReducer);
  const mergedDefaultSettings = useMemo(() => {
    const tenantPrimary = tenantDetail?.primaryColor;
    const configPrimary = baseSettings?.primaryColor || 'preset3';

    return {
      ...(baseSettings || {}),
      primaryColor: tenantPrimary || configPrimary,
    };
  }, [baseSettings, tenantDetail?.primaryColor]);

  const { state, setState, resetState, setField } = useLocalStorage(
    storageKey,
    mergedDefaultSettings
  );

  useEffect(() => {
    if (tenantDetail?.primaryColor) {
      setField('primaryColor', tenantDetail.primaryColor);
    }
  }, [tenantDetail?.primaryColor]);

  const [openDrawer, setOpenDrawer] = useState(false);

  const onToggleDrawer = useCallback(() => {
    setOpenDrawer((prev) => !prev);
  }, []);

  const onCloseDrawer = useCallback(() => {
    setOpenDrawer(false);
  }, []);

  const canReset = !isEqual(state, mergedDefaultSettings);

  const onReset = useCallback(() => {
    resetState(mergedDefaultSettings);
  }, [mergedDefaultSettings, resetState]);

  const memoizedValue = useMemo(
    () => ({
      canReset,
      onReset,
      openDrawer,
      onCloseDrawer,
      onToggleDrawer,
      state,
      setState,
      setField,
    }),
    [canReset, onReset, openDrawer, onCloseDrawer, onToggleDrawer, state, setField, setState]
  );

  return <SettingsContext.Provider value={memoizedValue}>{children}</SettingsContext.Provider>;
}

