          <DialogActions sx={{ justifyContent: 'flex-start' }}>
            <LoadingButton
              variant="contained"
              color="primary"
              loading={isSubmitting || isLoading}
              onClick={onSubmit}
            >
              Save
            </LoadingButton>
            <Button variant="outlined" color="error" onClick={onClose}>
              Cancel
            </Button>
          </DialogActions>
        </FormProvider>
      )}
    </Dialog>
  );
}

import {
  Box,
  Button,
  Card,
  LinearProgress,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableRow,
} from '@mui/material';
import { useSetState } from 'minimal-shared/hooks';
import { useCallback, useEffect, useState } from 'react';
import { CustomBreadcrumbs } from 'src/components/custom-breadcrumbs';
import { Iconify } from 'src/components/iconify';
import { toast } from 'src/components/snackbar';
import {
  emptyRows,
  getComparator,
  rowInPage,
  TableEmptyRows,
  TableHeadCustom,
  TableNoData,
  TablePaginationCustom,
  useTable,
} from 'src/components/table';
import { DashboardContent } from 'src/layouts/dashboard';
import { RouterLink } from 'src/routes/components';
import { paths } from 'src/routes/paths';
import { TableToolbar } from 'src/sections/table-toolbar';
import ApiService from 'src/services/ApiService';

import { ClassDialog } from '../class-dialog';
import { ClassTableRow } from '../class-table-row';
import { SubjectDialog } from '../subject-dialog';

const FILTEREDTABLEHEAD = [
  { id: 'className', label: 'Class Name' },
  { id: 'sections', label: 'Sections' },
  { id: 'annualFee', label: 'Annual Fee' },
];

const TABLEHEAD = [
  ...FILTEREDTABLEHEAD,
  { id: '', label: 'Action', sortBy: false, sx: { textAlign: 'center' } },
];

export function ClassListView() {
  const table = useTable({ defaultOrderBy: 'updatedDate', defaultOrder: 'desc' });
  const [isLoading, setIsLoading] = useState(false);
  const [tableData, setTableData] = useState([]);
  const [openDialog, setOpenDialog] = useState(false);
  const [openSubjectDialog, setOpenSubjectDialog] = useState(false);

  const filters = useSetState({
    search: '',
  });

  const { state: currentFilters, setState: updateFilters } = filters;

  const dataInPage = rowInPage(tableData, table.page, table.rowsPerPage);

  useEffect(() => {
    getClassList();
  }, []);

  const getClassList = async () => {
    setIsLoading(true);
    const { data } = await ApiService.getClassListAsync();
    if (data) {
      setTableData(data);
    }
    setIsLoading(false);
  };

  const dataFiltered = applyFilter({
    inputData: tableData,
    comparator: getComparator(table.order, table.orderBy),
    filters: currentFilters,
  });

  const handleFilterChange = (value) => {
    updateFilters({ search: value });
    table.onResetPage();
  };

  const OpenDialog = () => {
    setOpenDialog(true);
  };

  const OpenSubjectDialog = () => {
    setOpenSubjectDialog(true);
  };

  const toggleOpenDialog = () => setOpenDialog(!openDialog);

  const handleRefresh = () => {
    getClassList();
  };

  const onDeleteRow = useCallback(
    async (classId) => {
      const { data, errors } = await ApiService.deleteClassAsync(classId);
      if (data) {
        setTableData((prev) => prev.filter((row) => row.classId !== classId));
        toast.success('Class deleted successfully.');
        table.onUpdatePageDeleteRow(dataInPage.length);
      } else if (errors) {
        toast.error(errors[0].msg);
      }
      return data;
    },
    [table, dataInPage.length]
  );

  return (
    <DashboardContent>
      <CustomBreadcrumbs
        heading="Manage Class"
        links={[
          { name: 'Dashboard', href: '' },
          { name: 'Class', href: paths.dashboard.class.list },
        ]}
        action={
          <Stack direction="row" spacing={2}>
            <Button
              type="button"
              color="primary"
              variant="outlined"
              aria-haspopup="true"
              sx={{ whiteSpace: 'nowrap' }}
              startIcon={<Iconify icon="mingcute:add-line" />}
              onClick={OpenSubjectDialog}
            >
              Add Subject
            </Button>
            <Button
              variant="contained"
              color="primary"
              startIcon={<Iconify icon="mingcute:add-line" />}
              onClick={OpenDialog}
            >
              New Class
            </Button>
          </Stack>
        }
        sx={{ mb: 2 }}
      />

      <Card>
        <TableToolbar
          filters={filters}
          onFilterChange={handleFilterChange}
          placeholder="Search Class"
        />

        <TableContainer sx={{ height: 'calc(100vh - 40vh)' }}>
          <Box sx={{ position: 'relative' }}>
            <Table stickyHeader size={table.dense ? 'small' : 'medium'}>
              <TableHeadCustom
                order={table.order}
                orderBy={table.orderBy}
                headCells={TABLEHEAD}
                rowCount={dataFiltered.length}
                numSelected={table.selected.length}
                onSort={table.onSort}
              />

              {isLoading ? (
                <TableBody>
                  <TableRow>
                    <TableCell colSpan={TABLEHEAD.length}>
                      <Stack alignItems="center" justifyContent="center" sx={{ py: 5 }}>
                        <LinearProgress
                          sx={{
                            width: '50%',
                            maxWidth: 300,
                          }}
                        />
                      </Stack>
                    </TableCell>
                  </TableRow>
                </TableBody>
              ) : (
                <TableBody>
                  <TableNoData notFound={dataFiltered.length === 0} label="No Class Found." />
                  {dataFiltered.map((row) => (
                    <ClassTableRow
                      key={row.classId}
                      row={row}
                      selected={table.selected.includes(row.classId)}
                      onDeleteRow={() => onDeleteRow(row.classId)}
                      onSuccess={handleRefresh}
                    />
                  ))}

                  <TableEmptyRows
                    height={table.dense ? 56 : 76}
                    emptyRows={emptyRows(table.page, table.rowsPerPage, dataFiltered.length)}
                  />
                </TableBody>
              )}
            </Table>
          </Box>
        </TableContainer>
      </Card>

      <ClassDialog
        open={openDialog}
        onClose={() => setOpenDialog(false)}
        onSuccess={handleRefresh}
      />

      <SubjectDialog
        open={openSubjectDialog}
        onClose={() => setOpenSubjectDialog(false)}
        onSuccess={handleRefresh}
      />
    </DashboardContent>
  );
}

function applyFilter({ inputData, comparator, filters }) {
  const { search } = filters;
  const stabilizedThis = inputData.map((el, index) => [el, index]);

  stabilizedThis.sort((a, b) => {
    const order = comparator(a[0], b[0]);
    return order !== 0 ? order : a[1] - b[1];
  });

  let filteredData = stabilizedThis.map((el) => el[0]);

  if (search) {
    const lower = search.toLowerCase();
    filteredData = filteredData.filter((item) =>
      [item.className].filter(Boolean).some((value) => value.toLowerCase().includes(lower))
    );
  }
  return filteredData;
}

import { zodResolver } from '@hookform/resolvers/zod';
import LoadingButton from '@mui/lab/LoadingButton';
import {
  Autocomplete,
  Box,
  Button,
  Card,
  Checkbox,
  Chip,
  IconButton,
  InputAdornment,
  MenuItem,
  Stack,
  TextField,
} from '@mui/material';
import Grid from '@mui/material/Grid2';
import { useBoolean } from 'minimal-shared/hooks';
import { useEffect, useState } from 'react';
import { Controller, useForm } from 'react-hook-form';
import { isValidPhoneNumber } from 'react-phone-number-input';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router';
import { Field, Form, schemaHelper } from 'src/components/hook-form';
import { Iconify } from 'src/components/iconify';
import { LoadingScreen } from 'src/components/loading-screen';
import { toast } from 'src/components/snackbar';
import { useParams } from 'src/routes/hooks';
import apiService from 'src/services/ApiService';
import constants from 'src/utils/constants';
import { z as zod } from 'zod';

const TeacherSchema = zod.object({
  firstName: zod.string().min(1, { message: 'First Name is required.' }),
  lastName: zod.string().min(1, { message: 'Last Name is required.' }),
  email: zod
    .string()
    .min(1, { message: 'Email is required.' })
    .email({ message: 'Email must be valid.' }),
  mobileNo: schemaHelper.phoneNumber({ isValid: isValidPhoneNumber }),
  roleId: zod.coerce.number().refine((val) => val > 0, { message: 'Role is required.' }),
  employmentTypeId: zod.coerce
    .number()
    .refine((val) => val > 0, { message: 'Employment Type is required.' }),
  gender: zod.string().min(1, { message: 'Gender is required.' }),
  joiningDate: zod.string().min(1, { message: 'Joining Date is required.' }),
  qualification: zod.array(zod.string()).optional(),
  dateOfBirth: zod.string().optional(),
  addressLine1: zod.string().optional(),
  city: zod.string().optional(),
  state: zod.string().optional(),
  postalCode: zod.string().optional(),
  teacherClasses: zod
    .array(
      zod.object({
        classId: zod.number(),
        sectionId: zod.number().nullable().optional(),
      })
    )
    .optional(),
  teacherSubjects: zod
    .array(
      zod.object({
        subjectId: zod.number(),
      })
    )
    .optional(),
});

const TeacherAddSchema = TeacherSchema.extend({
  password: zod
    .string()
    .min(1, { message: 'Password is required.' })
    .min(8, { message: 'Password must be at least 8 characters.' }),
});

export function TeacherSaveForm() {
  const navigate = useNavigate();
  const { id } = useParams();
  const [roles, setRoles] = useState([]);
  const [employmentTypes, setEmploymentTypes] = useState([]);
  const [subjects, setSubjects] = useState([]);
  const [classMasters, setClassMasters] = useState([]);

  const showPassword = useBoolean();

  const defaultValues = {
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    mobileNo: '',
    roleId: '',
    employmentTypeId: '',
    gender: '',
    dateOfBirth: '',
    joiningDate: '',
    qualification: [],
    addressLine1: '',
    city: '',
    state: '',
    postalCode: '',
    teacherClasses: [],
    teacherSubjects: [],
  };

  const methods = useForm({
    mode: 'onSubmit',
    resolver: zodResolver(id ? TeacherSchema : TeacherAddSchema),
    defaultValues,
  });

  const {
    control,
    setError,
    handleSubmit,
    watch,
    setValue,
    formState: { isSubmitting, isLoading, errors },
  } = methods;

  useEffect(() => {
    const fetchData = async () => {
      const [rolesRes, employmentRes, subjectRes, classRes] = await Promise.all([
        apiService.getRolesAsync(),
        apiService.getEmploymentTypeAsync(),
        apiService.getSubjectAsync(),
        apiService.getAllClassMasterSectionsAsync(),
      ]);

      setRoles(rolesRes.data);
      setEmploymentTypes(employmentRes.data);
      setSubjects(subjectRes.data);
      setClassMasters(classRes.data);

      if (id) {
        const { data } = await apiService.getTeacherDataByIdAsync(id);

        methods.reset({
          ...data,
          qualification: data.qualification ? data.qualification.split(',') : [],
          teacherSubjects: subjectRes.data.filter((s) =>
            data.teacherSubjects.some((ts) => ts.subjectId === s.subjectId)
          ),
          teacherClasses: classRes.data.filter((c) =>
            data.teacherClasses.some(
              (tc) => tc.classId === c.classId && (tc.sectionId ?? null) === (c.sectionId ?? null)
            )
          ),
        });
      }
    };

    fetchData();
  }, [id, methods]);

  const onSubmit = handleSubmit(async (values) => {
    const payload = {
      ...values,
      qualification: (values.qualification || []).join(','),
      teacherClasses: values.teacherClasses.map((tc) => ({
        classId: tc.classId,
        sectionId: tc.sectionId ?? null,
      })),
      teacherSubjects: values.teacherSubjects.map((ts) => ({
        subjectId: ts.subjectId,
      })),
      ...(id && { teacherId: Number(id) }),
    };
    const response = await apiService.saveTeacherAsync(payload);
    if (response.data) {
      toast.success(id ? 'Teacher updated successfully.' : 'Teacher created successfully.');
      navigate(-1);
      return;
    }
    if (response.error) {
      setError(response.error.param, {
        message: response.error.msg,
      });
    }
  });

  return (
    <>
      {isLoading ? (
        <LoadingScreen />
      ) : (
        <>
          <Form methods={methods} onSubmit={onSubmit}>
            <Grid container spacing={2}>
              <Grid size={{ xs: 12, md: 8 }}>
                <Card sx={{ p: 3 }}>
                  <Stack direction="column" spacing={2}>
                    <Box
                      sx={{
                        rowGap: 3,
                        columnGap: 2,
                        display: 'grid',
                        gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(2, 1fr)' },
                      }}
                    >
                      <Field.Text maxLength={50} name="firstName" label="First Name" />
                      <Field.Text maxLength={50} name="lastName" label="Last Name" />
                      <Field.Text name="email" label="Email" />
                      {!id && (
                        <Field.Text
                          name="password"
                          label="Password"
                          placeholder="8+ characters"
                          type={showPassword.value ? 'text' : 'password'}
                          slotProps={{
                            htmlInput: { minLength: 8, maxLength: 25 },
                            inputLabel: { shrink: true },
                            input: {
                              endAdornment: (
                                <InputAdornment position="end">
                                  <IconButton onClick={showPassword.onToggle} edge="end">
                                    <Iconify
                                      icon={
                                        showPassword.value
                                          ? 'solar:eye-bold'
                                          : 'solar:eye-closed-bold'
                                      }
                                    />
                                  </IconButton>
                                </InputAdornment>
                              ),
                            },
                          }}
                        />
                      )}
                      <Field.Phone
                        name="mobileNo"
                        label="Mobile Number"
                        country={constants.defaultCountryCode}
                        disableCountryCode={true}
                      />
                      <Field.Select name="roleId" label="Role">
                        {roles.map((option) => (
                          <MenuItem key={option.roleId} value={option.roleId}>
                            {option.roleName}
                          </MenuItem>
                        ))}
                      </Field.Select>
                      <Field.Select name="employmentTypeId" label="Employment Type">
                        {employmentTypes.map((option) => (
                          <MenuItem key={option.employmentTypeId} value={option.employmentTypeId}>
                            {option.employmentType}
                          </MenuItem>
                        ))}
                      </Field.Select>
                      <Field.Select name="gender" label="Gender">
                        <MenuItem value="M">Male</MenuItem>
                        <MenuItem value="F">Female</MenuItem>
                        <MenuItem value="O">Other</MenuItem>
                      </Field.Select>
                      <Field.DatePicker
                        name="dateOfBirth"
                        label="Date of Birth"
                        allowFutureDates={true}
                        allowPastDates={true}
                      />
                      <Field.DatePicker
                        name="joiningDate"
                        label="Joining Date"
                        allowFutureDates={true}
                        allowPastDates={true}
                      />
                      <Autocomplete
                        multiple
                        freeSolo
                        options={[]}
                        value={watch('qualification') || []}
                        onChange={(event, newValue) => {
                          setValue('qualification', newValue);
                        }}
                        renderInput={(params) => <TextField {...params} label="Qualification" />}
                        renderTags={(selected = [], getTagProps) =>
                          selected.map((option, index) => (
                            <Chip
                              {...getTagProps({ index })}
                              key={option}
                              label={option}
                              size="small"
                              variant="soft"
                            />
                          ))
                        }
                      />
                      <Field.Text name="addressLine1" label="Address" />
                      <Field.Text name="city" label="City" />
                      <Field.Text name="state" label="State" />
                      <Field.Text name="postalCode" label="Postal Code" />
                    </Box>
                  </Stack>
                </Card>
              </Grid>

              <Grid size={{ xs: 12, md: 4 }}>
                <Card sx={{ p: 3 }}>
                  <Stack direction="column" spacing={2}>
                    <Box
                      sx={{
                        rowGap: 3,
                        columnGap: 1,
                        display: 'grid',
                        gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(1, 1fr)' },
                      }}
                    >
                      <Controller
                        name="teacherSubjects"
                        control={control}
                        render={({ field }) => (
                          <Autocomplete
                            {...field}
                            fullWidth
                            multiple
                            disableCloseOnSelect
                            options={subjects}
                            getOptionLabel={(option) => option.subjectName}
                            onChange={(event, newValue) => field.onChange(newValue)}
                            isOptionEqualToValue={(option, value) =>
                              option.subjectId === value.subjectId
                            }
                            renderInput={(params) => (
                              <TextField
                                {...params}
                                label="Subjects"
                                placeholder="Subjects"
                                error={!!errors.teacherSubjects}
                                helperText={
                                  errors.teacherSubjects ? errors.teacherSubjects.message : ''
                                }
                              />
                            )}
                            renderOption={(props, option) => {
                              const isSelected = field.value.some(
                                (selected) => selected.subjectId === option.subjectId
                              );
                              return (
                                <li {...props} key={option.subjectId}>
                                  <Checkbox size="small" disableRipple checked={isSelected} />
                                  {option.subjectName}
                                </li>
                              );
                            }}
                            renderTags={(selected, getTagProps) =>
                              selected.map((option, index) => (
                                <Chip
                                  {...getTagProps({ index })}
                                  key={option.subjectId}
                                  label={option.subjectName}
                                  size="small"
                                  variant="soft"
                                />
                              ))
                            }
                          />
                        )}
                      />
                      <Controller
                        name="teacherClasses"
                        control={control}
                        render={({ field }) => (
                          <Autocomplete
                            {...field}
                            fullWidth
                            multiple
                            disableCloseOnSelect
                            options={classMasters}
                            value={field.value || []}
                            onChange={(event, newValue) => field.onChange(newValue)}
                            getOptionLabel={(option) =>
                              option.sectionName
                                ? `${option.className} - ${option.sectionName}`
                                : option.className
                            }
                            isOptionEqualToValue={(option, value) =>
                              option.classId === value.classId &&
                              option.sectionId === value.sectionId
                            }
                            renderInput={(params) => (
                              <TextField
                                {...params}
                                label="Classes"
                                placeholder="Classes"
                                error={!!errors.teacherClasses}
                                helperText={errors.teacherClasses?.message}
                              />
                            )}
                            renderOption={(props, option) => {
                              const isSelected = (field.value || []).some(
                                (selected) =>
                                  selected.classId === option.classId &&
                                  selected.sectionId === option.sectionId
                              );

                              return (
                                <li
                                  {...props}
                                  key={`${option.classId}-${option.sectionId ?? 'null'}`}
                                >
                                  <Checkbox size="small" disableRipple checked={isSelected} />
                                  {option.sectionName
                                    ? `${option.className} - ${option.sectionName}`
                                    : option.className}
                                </li>
                              );
                            }}
                            renderTags={(selected, getTagProps) =>
                              (selected || []).map((option, index) => (
                                <Chip
                                  {...getTagProps({ index })}
                                  key={`${option.classId}-${option.sectionId ?? 'null'}`}
                                  label={
                                    option.sectionName
                                      ? `${option.className} - ${option.sectionName}`
                                      : option.className
                                  }
                                  size="small"
                                  variant="soft"
                                />
                              ))
                            }
                          />
                        )}
                      />
                    </Box>
                  </Stack>
                </Card>
              </Grid>
              <Grid item size={{ xs: 12, md: 8 }}>
                <Stack direction="row" justifyContent="space-between">
                  <Stack direction="row" spacing={2}>
                    <LoadingButton
                      type="submit"
                      variant="contained"
                      color="primary"
                      loading={isSubmitting}
                    >
                      Save
                    </LoadingButton>
                    <Button
                      disabled={isSubmitting}
                      variant="outlined"
                      color="error"
                      onClick={() => navigate(-1)}
                    >
                      Cancel
                    </Button>
                  </Stack>
                </Stack>
              </Grid>
            </Grid>
          </Form>
        </>
      )}
    </>
  );
}

import { LoadingButton } from '@mui/lab';
import { Avatar, Box, IconButton, Stack, TableCell, TableRow, Tooltip } from '@mui/material';
import { useBoolean } from 'minimal-shared/hooks';
import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { ConfirmDialog } from 'src/components/custom-dialog';
import { Iconify } from 'src/components/iconify';
import { RouterLink } from 'src/routes/components';
import { paths } from 'src/routes/paths';
import dateHelper from 'src/utils/dateHelper';
import enums from 'src/utils/enums';
import utils from 'src/utils/utils';

export function TeacherTableRow({ row, selected, onDeleteRow, isProfile }) {
  const confirmDialog = useBoolean();
  const [loading, setLoading] = useState(false);

  const methods = useForm({
    defaultValues: {
      authChoice: 'backup',
    },
  });

  const renderConfirmDialog = () => (
    <ConfirmDialog
      open={confirmDialog.value}
      onClose={confirmDialog.onFalse}
      title="Delete Teacher"
      content={<>Are you sure want to delete {row.teacherName}?</>}
      action={
        <LoadingButton
          variant="contained"
          color="error"
          loading={loading}
          onClick={() => {
            utils.handleConfirmDelete({
              setLoading,
              onDeleteRow,
              confirmDialog,
            });
          }}
        >
          Delete
        </LoadingButton>
      }
    />
  );

  return (
    <>
      <TableRow hover selected={selected} aria-checked={selected} tabIndex={-1}>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Avatar
              alt={row.teacherName}
              src={row.imagePath}
              sx={{ bgcolor: 'primary.main', color: 'white' }}
            >
              {row.teacherName.charAt(0).toUpperCase()}
            </Avatar>
            <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body2' }}>
                {`${row.teacherName}`}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex' }}>
            <Stack sx={{ typography: 'body2', flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit' }}>
                {row.email}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ typography: 'body2', flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit' }}>
                {row.mobileNo}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ typography: 'body2', flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit' }}>
                {enums.displayRole[row.roleId]}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body2' }}>
                {row.lastLoginOn ? `${dateHelper.formatDateTime(row.lastLoginOn)}` : '-'}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body2' }}>
                {row.updatedBy ?? ''}
              </Box>
              <Box component="span" sx={{ color: 'text.disabled' }}>
                {dateHelper.formatDateTime(row.updatedDate)}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          {!isProfile && (
            <Box sx={{ display: 'flex', justifyContent: 'center', gap: 1 }}>
              <Tooltip title="Edit" placement="top" arrow>
                <IconButton
                  component={RouterLink}
                  href={paths.dashboard.teacher.edit(row.teacherId)}
                  color="primary"
                >
                  <Iconify icon="solar:pen-bold" />
                </IconButton>
              </Tooltip>
              <Tooltip title="Delete" placement="top" arrow>
                <IconButton color="error" onClick={() => confirmDialog.onTrue()}>
                  <Iconify icon="solar:trash-bin-trash-bold" />
                </IconButton>
              </Tooltip>
            </Box>
          )}
        </TableCell>
      </TableRow>
      {renderConfirmDialog()}
    </>
  );
}

import { CustomBreadcrumbs } from 'src/components/custom-breadcrumbs';
import { DashboardContent } from 'src/layouts/dashboard';
import { paths } from 'src/routes/paths';
import { useSelector } from 'react-redux';

import { TeacherSaveForm } from '../teacher-save-form';

export function ProfileEditView() {
  const { loggedInTeacher } = useSelector((state) => state.AuthReducer);
  return (
    <DashboardContent>
      <CustomBreadcrumbs
        heading="Edit Profile"
        links={[{ name: 'Dashboard', href: paths.dashboard.root }, { name: 'Edit Profile' }]}
        sx={{ mb: { xs: 2, md: 2 } }}
      />
      <TeacherSaveForm />
    </DashboardContent>
  );
}
